 12→/**
 13→ * Returns a flow that ignores first [count] elements.
 14→ * Throws [IllegalArgumentException] if [count] is negative.
 15→ */
 16→public fun <T> Flow<T>.drop(count: Int): Flow<T> {
 17→    require(count >= 0) { "Drop count should be non-negative, but had $count" }
 18→    return flow {
 19→        var skipped = 0
 20→        collect { value ->
 21→            if (skipped >= count) emit(value) else ++skipped
 22→        }
 23→    }
 24→}
