 26→/**
 27→ * Returns a flow containing all elements except first elements that satisfy the given predicate.
 28→ */
 29→public fun <T> Flow<T>.dropWhile(predicate: suspend (T) -> Boolean): Flow<T> = flow {
 30→    var matched = false
 31→    collect { value ->
 32→        if (matched) {
 33→            emit(value)
 34→        } else if (!predicate(value)) {
 35→            matched = true
 36→            emit(value)
 37→        }
 38→    }
 39→}
